public static void sort(int[] arr, int lo, int hi) {
    if (hi - lo < 2) {
        return;
    }
    int mi = (hi + lo) / 2;
    int x = arr[mi];
    arr[mi] = arr[hi];
    arr[hi] = x;
    int i = lo;
    for (int j = lo; j < hi; j++) {
        if (arr[j] < x) {
            int y = arr[i];
            arr[i] = arr[j];
            arr[j] = y;
            i++;
        }
    }
    int y = arr[i];
    arr[i] = arr[hi];
    arr[hi] = y;
    sort(arr, lo, i - 1);
    sort(arr, i + 1, hi);
} [/INST]
public static void sort(int[] arr, int lo, int hi) {
    if (hi - lo < 2) {
        return;
    }
    int mi = (hi + lo) / 2;
    int x = arr[mi];
    arr[mi] = arr[hi];
    arr[hi] = x;
    int i = lo;
    for (int j = lo; j < hi; j++) {
        if (arr[j] < x) {
            int y = arr[i];
            arr[i] = arr[j];
            arr[j] = y;
            i++;
        }
    }
    int y = arr[i];
    arr[i] = arr[hi];
    arr[hi] = y;
    sort(arr, lo, i);
    sort(arr, i + 1, hi);
}

