public static boolean hasPath(int[][] maze, int[] start, int[] end) {
    if (maze == null || maze.length == 0) {
        return false;
    }
    int m = maze.length;
    int n = maze[0].length;
    boolean[][] visited = new boolean[m][n];
    return hasPath(maze, start, end, visited);
}

private static boolean hasPath(int[][] maze, int[] start, int[] end, boolean[][] visited) {
    if (start[0] == end[0] && start[1] == end[1]) {
        return true;
    }
    int m = maze.length;
    int n = maze[0].length;
    int[][] dirs = {{0, 1}, {0, -1}, {1, 0}, {-1, 0}};
    for (int[] dir : dirs) {
        int nextX = start[0] + dir[0];
        int nextY = start[1] + dir[1];
        if (nextX >= 0 && nextX < m && nextY >= 0 && nextY < n && maze[nextX][nextY] == 0 && !visited[nextX][nextY]) {
            visited[nextX][nextY] = true;
            if (hasPath(maze, new int[]{nextX, nextY}, end, visited)) {
                return true;
            }
        }
    }
    return false;
}

