        return false;
    }
    int left = 0;
    int right = n;
    while (left <= right) {
        int mid = (left + right) / 2;
        if (mid * mid == n) {
            return true;
        }
        else if (mid * mid < n) {
            left = mid + 1;
        }
        else {
            right = mid - 1;
        }
    }
    return false;
