public boolean isSquare(int n) {
    if (n < 0) {
        return false;
    }
    int left = 0;
    int right = n;
    while (left < right) {
        int mid = left + (right - left) / 2;
        if (mid * mid == n) {
            return true;
        }
        else if (mid * mid < n) {
            left = mid + 1;
        }
        else {
            right = mid;
        }
    }
    return left * left == n;
}

