public int countEvenOddNodes(TreeNode root) {
    if (root == null) {
        return 0;
    }
    int evenSum = 0;
    int oddSum = 0;
    Queue<TreeNode> q = new LinkedList<TreeNode>();
    q.offer(root);
    while (!q.isEmpty()) {
        TreeNode curr = q.poll();
        if (curr.val % 2 == 0) {
            evenSum++;
        } else {
            oddSum++;
        }
        if (curr.left != null) {
            q.offer(curr.left);
        }
        if (curr.right != null) {
            q.offer(curr.right);
        }
    }
    return evenSum - oddSum;
