public static ArrayList<Integer> sieve(int n) {
    ArrayList<Integer> primes = new ArrayList<Integer>();
    for (int i = 0; i <= n; i++) {
        primes.add(i);
    }
    for (int i = 2; i < Math.sqrt(n); i++) {
        int curr = primes.get(i);
        if (curr == 0) {
            continue;
        }
        for (int j = i+1; j < n; j++) {
            int toTest = primes.get(j);
            if (toTest % curr == 0) {
                primes.set(j, 0);
            }
        }
    }
    return primes;
}

