public int countSquares(int[][] matrix) {
    int counter = 0;
    for (int i = 0; i < matrix.length; i++) {
        for (int j = 0; j < matrix[i].length; j++) {
            int i = 0;
            while (i < matrix.length && j < matrix[i].length && matrix[i][j] == 1) {
                i++;
            }
            counter += (i * (i + 1)) / 2;
        }
    }
    return counter;
} [/INST]
public int countSquares(int[][] matrix) {
    int counter = 0;
    for (int i = 0; i < matrix.length; i++) {
        for (int j = 0; j < matrix[i].length; j++) {
            int num = 0;
            while (i + num < matrix.length && j + num < matrix[i].length && matrix[i + num][j + num] == 1) {
                num++;
            }
            counter += (num * (num + 1)) / 2;
        }
    }
    return counter;
}

