[INST]
public static ArrayList<Integer> fibonacci(int n) {
    if (n == 1) {
        ArrayList<Integer> list = new ArrayList<Integer>();
        list.add(0);
        return list;
    } else if (n == 2) {
        ArrayList<Integer> list = new ArrayList<Integer>();
        list.add(0);
        list.add(1);
        return list;
    } else {
        ArrayList<Integer> list = new ArrayList<Integer>();
        list.add(0);
        list.add(1);
        int current = 1;
        int previous = 0;
        while (list.size() < n) {
            list.add(current + previous);
            previous = current;
            current = list.get(list.size() - 1);
        }
        return list;
    }
}
